    if (trim($value) !== '') {
        $stmt = $db->prepare("REPLACE INTO links (key, value) VALUES (:key, :value)");
        $stmt->bindValue(':key', $key, SQLITE3_TEXT);
        $stmt->bindValue(':value', $value, SQLITE3_TEXT);
        $stmt->execute();
    }
}

echo "Saved non-empty values.";
